import os
import time
import random
from flask import Flask, request, jsonify, Response
from prometheus_client import (
    Counter,
    Gauge,
    Histogram,
    Summary,
    generate_latest,
    CONTENT_TYPE_LATEST,
    CollectorRegistry,
    multiprocess,
)

def create_app():
    app = Flask(__name__)

    # --- Prometheus registry (supports multiprocess via gunicorn) ---
    registry = CollectorRegistry()
    if os.environ.get("PROMETHEUS_MULTIPROC_DIR"):
        multiprocess.MultiProcessCollector(registry)

    # --- Metrics ---
    REQUESTS_TOTAL = Counter(
        "http_requests_total",
        "Total HTTP requests",
        ["method", "endpoint", "http_status"],
        registry=registry,
    )

    REQUEST_IN_PROGRESS = Gauge(
        "http_requests_in_progress",
        "In-progress HTTP requests",
        ["endpoint"],
        registry=registry,
    )

    REQUEST_LATENCY_SECONDS = Histogram(
        "http_request_latency_seconds",
        "HTTP request latency in seconds",
        ["method", "endpoint"],
        buckets=(0.005, 0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1, 2.5, 5, 10),
        registry=registry,
    )

    RESPONSE_SIZE_BYTES = Histogram(
        "http_response_size_bytes",
        "HTTP response size in bytes",
        ["endpoint"],
        buckets=(100, 500, 1_000, 5_000, 10_000, 50_000, 100_000, 500_000, 1_000_000),
        registry=registry,
    )

    # Business metrics (example)
    ORDERS_CREATED_TOTAL = Counter(
        "business_orders_created_total",
        "Total number of orders created",
        ["result"],
        registry=registry,
    )

    ACTIVE_USERS = Gauge(
        "business_active_users",
        "Current number of active users (example gauge)",
        registry=registry,
    )

    ORDER_VALUE_SECONDS = Histogram(
        "business_order_processing_seconds",
        "Order processing time in seconds (example histogram)",
        buckets=(0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1, 2.5, 5),
        registry=registry,
    )

    CHECKOUT_VALUE = Summary(
        "business_checkout_value",
        "Checkout value summary (example summary)",
        registry=registry,
    )

    # --- Helpers ---
    def _endpoint_label():
        rule = request.url_rule.rule if request.url_rule else "unmatched"
        return rule

    @app.before_request
    def _before_request():
        request._start_time = time.perf_counter()
        request._endpoint_label = _endpoint_label()
        REQUEST_IN_PROGRESS.labels(endpoint=request._endpoint_label).inc()

    @app.after_request
    def _after_request(response):
        try:
            endpoint = getattr(request, "_endpoint_label", _endpoint_label())
            method = request.method
            status = str(response.status_code)

            elapsed = time.perf_counter() - getattr(request, "_start_time", time.perf_counter())
            REQUEST_LATENCY_SECONDS.labels(method=method, endpoint=endpoint).observe(elapsed)
            REQUESTS_TOTAL.labels(method=method, endpoint=endpoint, http_status=status).inc()

            if response.direct_passthrough:
                size = 0
            else:
                data = response.get_data(as_text=False)
                size = len(data) if data is not None else 0
            RESPONSE_SIZE_BYTES.labels(endpoint=endpoint).observe(size)
        finally:
            REQUEST_IN_PROGRESS.labels(endpoint=getattr(request, "_endpoint_label", _endpoint_label())).dec()
        return response

    @app.route("/metrics")
    def metrics():
        if os.environ.get("PROMETHEUS_MULTIPROC_DIR"):
            multiprocess.mark_process_dead(os.getpid())
        data = generate_latest(registry)
        return Response(data, mimetype=CONTENT_TYPE_LATEST)

    @app.route("/healthz")
    def healthz():
        return jsonify(status="ok")

    @app.route("/")
    def index():
        return jsonify(service="flask-prometheus", status="running")

    @app.route("/simulate_activity", methods=["POST"])
    def simulate_activity():
        # Example endpoint to mutate business metrics
        payload = request.get_json(silent=True) or {}
        active_users = payload.get("active_users")
        if active_users is not None:
            try:
                ACTIVE_USERS.set(float(active_users))
            except Exception:
                pass

        # Simulate an "order" processing
        start = time.perf_counter()
        time.sleep(float(payload.get("sleep", random.uniform(0.01, 0.15))))
        duration = time.perf_counter() - start
        ORDER_VALUE_SECONDS.observe(duration)

        # Simulate order result
        result = payload.get("result", random.choice(["success", "failure"]))
        if result not in ("success", "failure"):
            result = "failure"
        ORDERS_CREATED_TOTAL.labels(result=result).inc()

        # Simulate checkout value
        value = payload.get("value", random.uniform(10, 250))
        try:
            CHECKOUT_VALUE.observe(float(value))
        except Exception:
            pass

        return jsonify(
            ok=True,
            observed={
                "order_processing_seconds": duration,
                "result": result,
                "checkout_value": value,
                "active_users": active_users,
            },
        )

    return app


app = create_app()

if __name__ == "__main__":
    host = os.environ.get("HOST", "0.0.0.0")
    port = int(os.environ.get("PORT", "8000"))
    app.run(host=host, port=port)